import SearchEngine from '../src/search/SearchEngine.js';
import CodebaseIndexer from '../src/indexer/CodebaseIndexer.js';
import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

describe('SearchEngine', () => {
  let searchEngine;
  let indexer;
  let fsManager;
  let testDir;

  beforeEach(async () => {
    // Create a temporary test directory
    testDir = path.join(__dirname, 'test-search-temp');
    await fs.mkdir(testDir, { recursive: true });

    // Create test files
    await fs.writeFile(
      path.join(testDir, 'file1.js'),
      `function hello() {
  // TODO: Implement this
  console.log('Hello World');
}

function goodbye() {
  console.log('Goodbye');
}`
    );

    await fs.writeFile(
      path.join(testDir, 'file2.js'),
      `const TODO = 'task';
function test() {
  return TODO;
}`
    );

    await fs.writeFile(
      path.join(testDir, 'file3.py'),
      `def hello():
    # TODO: Add error handling
    print("Hello")
    
def world():
    print("World")`
    );

    await fs.mkdir(path.join(testDir, 'src'), { recursive: true });
    await fs.writeFile(
      path.join(testDir, 'src', 'index.js'),
      `// Main entry point
export function main() {
  console.log('Starting application');
}`
    );

    // Initialize components
    fsManager = new FileSystemManager(testDir);
    indexer = new CodebaseIndexer(testDir, fsManager);
    await indexer.buildIndex();
    searchEngine = new SearchEngine(indexer);
  });

  afterEach(async () => {
    // Clean up test directory
    await fs.rm(testDir, { recursive: true, force: true });
  });

  describe('search', () => {
    test('should find text matches across files', async () => {
      const results = await searchEngine.search('TODO');
      
      expect(results.length).toBeGreaterThan(0);
      expect(results.some(r => r.filePath.includes('file1.js'))).toBe(true);
      expect(results.some(r => r.filePath.includes('file2.js'))).toBe(true);
      expect(results.some(r => r.filePath.includes('file3.py'))).toBe(true);
    });

    test('should return results with correct structure', async () => {
      const results = await searchEngine.search('TODO');
      
      expect(results.length).toBeGreaterThan(0);
      const result = results[0];
      
      expect(result).toHaveProperty('filePath');
      expect(result).toHaveProperty('lineNumber');
      expect(result).toHaveProperty('line');
      expect(result).toHaveProperty('context');
      expect(result.context).toHaveProperty('before');
      expect(result.context).toHaveProperty('after');
      expect(result).toHaveProperty('language');
      expect(result).toHaveProperty('score');
    });

    test('should include context lines', async () => {
      const results = await searchEngine.search('TODO', { contextLines: 2 });
      
      const result = results.find(r => r.filePath.includes('file1.js'));
      expect(result).toBeDefined();
      expect(result.context.before.length).toBeGreaterThan(0);
      expect(result.context.after.length).toBeGreaterThan(0);
    });

    test('should support case sensitive search', async () => {
      const results = await searchEngine.search('todo', { caseSensitive: true });
      
      // Should not find 'TODO' when searching for 'todo' with case sensitivity
      expect(results.length).toBe(0);
    });

    test('should support case insensitive search', async () => {
      const results = await searchEngine.search('todo', { caseSensitive: false });
      
      // Should find 'TODO' when searching for 'todo' without case sensitivity
      expect(results.length).toBeGreaterThan(0);
    });

    test('should support whole word matching', async () => {
      const results = await searchEngine.search('TODO', { wholeWord: true });
      
      // Should find standalone 'TODO' but not 'TODO' within other words
      expect(results.length).toBeGreaterThan(0);
      expect(results.every(r => /\bTODO\b/i.test(r.line))).toBe(true);
    });

    test('should return line numbers (1-indexed)', async () => {
      const results = await searchEngine.search('TODO');
      
      expect(results.every(r => r.lineNumber >= 1)).toBe(true);
    });

    test('should throw error for empty query', async () => {
      await expect(searchEngine.search('')).rejects.toThrow('Search query cannot be empty');
      await expect(searchEngine.search('   ')).rejects.toThrow('Search query cannot be empty');
    });

    test('should handle files with no matches', async () => {
      const results = await searchEngine.search('NONEXISTENT_STRING_XYZ');
      
      expect(results).toEqual([]);
    });

    test('should search in multiple file types', async () => {
      const results = await searchEngine.search('hello');
      
      const jsResults = results.filter(r => r.filePath.endsWith('.js'));
      const pyResults = results.filter(r => r.filePath.endsWith('.py'));
      
      expect(jsResults.length).toBeGreaterThan(0);
      expect(pyResults.length).toBeGreaterThan(0);
    });
  });

  describe('searchRegex', () => {
    test('should find regex pattern matches', async () => {
      const results = await searchEngine.searchRegex('function\\s+\\w+');
      
      expect(results.length).toBeGreaterThan(0);
      expect(results.some(r => r.line.includes('function hello'))).toBe(true);
    });

    test('should support regex flags', async () => {
      const results = await searchEngine.searchRegex('FUNCTION', { flags: 'gi' });
      
      // Should find 'function' with case-insensitive flag
      expect(results.length).toBeGreaterThan(0);
    });

    test('should throw error for invalid regex', async () => {
      await expect(searchEngine.searchRegex('[')).rejects.toThrow('Invalid regex pattern');
    });

    test('should throw error for empty pattern', async () => {
      await expect(searchEngine.searchRegex('')).rejects.toThrow('Search pattern cannot be empty');
    });

    test('should match complex patterns', async () => {
      const results = await searchEngine.searchRegex('console\\.log\\([\'"].*?[\'"]\\)');
      
      expect(results.length).toBeGreaterThan(0);
      expect(results.some(r => r.line.includes('console.log'))).toBe(true);
    });

    test('should include context lines for regex matches', async () => {
      const results = await searchEngine.searchRegex('function', { contextLines: 1 });
      
      const result = results[0];
      expect(result.context).toBeDefined();
      expect(result.context.before).toBeDefined();
      expect(result.context.after).toBeDefined();
    });
  });

  describe('filterByFileType', () => {
    test('should filter results by single extension', async () => {
      const results = await searchEngine.search('TODO');
      const filtered = searchEngine.filterByFileType(results, ['.js']);
      
      expect(filtered.every(r => r.filePath.endsWith('.js'))).toBe(true);
      expect(filtered.some(r => r.filePath.endsWith('.py'))).toBe(false);
    });

    test('should filter results by multiple extensions', async () => {
      const results = await searchEngine.search('hello');
      const filtered = searchEngine.filterByFileType(results, ['.js', '.py']);
      
      expect(filtered.every(r => 
        r.filePath.endsWith('.js') || r.filePath.endsWith('.py')
      )).toBe(true);
    });

    test('should handle extensions without leading dot', async () => {
      const results = await searchEngine.search('TODO');
      const filtered = searchEngine.filterByFileType(results, ['js']);
      
      expect(filtered.every(r => r.filePath.endsWith('.js'))).toBe(true);
    });

    test('should return all results when no extensions provided', async () => {
      const results = await searchEngine.search('TODO');
      const filtered = searchEngine.filterByFileType(results, []);
      
      expect(filtered).toEqual(results);
    });

    test('should be case insensitive for extensions', async () => {
      const results = await searchEngine.search('TODO');
      const filtered = searchEngine.filterByFileType(results, ['.JS']);
      
      expect(filtered.every(r => r.filePath.endsWith('.js'))).toBe(true);
    });
  });

  describe('filterByDirectory', () => {
    test('should filter results by directory path', async () => {
      const results = await searchEngine.search('console');
      const filtered = searchEngine.filterByDirectory(results, 'src');
      
      expect(filtered.every(r => r.filePath.startsWith('src/'))).toBe(true);
    });

    test('should handle directory path with trailing slash', async () => {
      const results = await searchEngine.search('console');
      const filtered = searchEngine.filterByDirectory(results, 'src/');
      
      expect(filtered.every(r => r.filePath.startsWith('src/'))).toBe(true);
    });

    test('should return all results when no directory provided', async () => {
      const results = await searchEngine.search('console');
      const filtered = searchEngine.filterByDirectory(results, '');
      
      expect(filtered).toEqual(results);
    });

    test('should handle nested directory paths', async () => {
      // Create nested directory
      await fs.mkdir(path.join(testDir, 'src', 'utils'), { recursive: true });
      await fs.writeFile(
        path.join(testDir, 'src', 'utils', 'helper.js'),
        'console.log("helper");'
      );
      
      await indexer.buildIndex();
      
      const results = await searchEngine.search('console');
      const filtered = searchEngine.filterByDirectory(results, 'src/utils');
      
      expect(filtered.every(r => r.filePath.startsWith('src/utils/'))).toBe(true);
    });

    test('should normalize backslashes to forward slashes', async () => {
      const results = await searchEngine.search('console');
      const filtered = searchEngine.filterByDirectory(results, 'src\\');
      
      expect(filtered.every(r => r.filePath.startsWith('src/'))).toBe(true);
    });
  });

  describe('rankResults', () => {
    test('should rank results by relevance', async () => {
      const results = await searchEngine.search('TODO');
      const ranked = searchEngine.rankResults(results, 'TODO');
      
      // Results should be sorted by score descending
      for (let i = 0; i < ranked.length - 1; i++) {
        expect(ranked[i].score).toBeGreaterThanOrEqual(ranked[i + 1].score);
      }
    });

    test('should boost exact matches', async () => {
      const results = await searchEngine.search('TODO');
      const ranked = searchEngine.rankResults(results, 'TODO');
      
      // Results with exact matches should have higher scores
      const exactMatch = ranked.find(r => r.line.toLowerCase().includes('todo'));
      expect(exactMatch).toBeDefined();
      expect(exactMatch.score).toBeGreaterThan(1.0);
    });

    test('should boost matches at start of line', async () => {
      await fs.writeFile(
        path.join(testDir, 'test-rank.js'),
        `TODO: This is at start
function test() {
  // TODO: This is not at start
}`
      );
      
      await indexer.buildIndex();
      
      const results = await searchEngine.search('TODO');
      const ranked = searchEngine.rankResults(results, 'TODO');
      
      const startMatch = ranked.find(r => 
        r.filePath.includes('test-rank.js') && r.line.trimStart().startsWith('TODO')
      );
      
      expect(startMatch).toBeDefined();
      expect(startMatch.score).toBeGreaterThan(1.0);
    });

    test('should boost matches in file name', async () => {
      await fs.writeFile(
        path.join(testDir, 'TODO.js'),
        'const x = 1;'
      );
      
      await indexer.buildIndex();
      
      const results = await searchEngine.search('x');
      const ranked = searchEngine.rankResults(results, 'TODO');
      
      const fileNameMatch = ranked.find(r => r.filePath.includes('TODO.js'));
      if (fileNameMatch) {
        expect(fileNameMatch.score).toBeGreaterThan(1.0);
      }
    });

    test('should penalize very long lines', async () => {
      const longLine = 'x'.repeat(300);
      await fs.writeFile(
        path.join(testDir, 'long.js'),
        `const data = "${longLine}";`
      );
      
      await indexer.buildIndex();
      
      const results = await searchEngine.search('data');
      const ranked = searchEngine.rankResults(results, 'data');
      
      const longLineResult = ranked.find(r => r.line.length > 200);
      if (longLineResult) {
        // Score should be reduced for long lines
        expect(longLineResult.score).toBeLessThan(2.0);
      }
    });

    test('should handle empty results', () => {
      const ranked = searchEngine.rankResults([], 'query');
      expect(ranked).toEqual([]);
    });

    test('should boost important files', async () => {
      await fs.writeFile(
        path.join(testDir, 'README.md'),
        'This is a readme file with some content'
      );
      
      await indexer.buildIndex();
      
      const results = await searchEngine.search('content');
      const ranked = searchEngine.rankResults(results, 'content');
      
      const readmeResult = ranked.find(r => r.filePath.includes('README'));
      if (readmeResult) {
        expect(readmeResult.score).toBeGreaterThan(1.0);
      }
    });

    test('should handle multiple query words', async () => {
      const results = await searchEngine.search('hello world');
      const ranked = searchEngine.rankResults(results, 'hello world');
      
      // Results matching both words should score higher
      expect(ranked.length).toBeGreaterThanOrEqual(0);
      if (ranked.length > 0) {
        expect(ranked[0].score).toBeGreaterThan(0);
      }
    });
  });

  describe('integration', () => {
    test('should support chaining filters and ranking', async () => {
      const results = await searchEngine.search('console');
      const filtered = searchEngine.filterByFileType(results, ['.js']);
      const ranked = searchEngine.rankResults(filtered, 'console');
      
      expect(ranked.every(r => r.filePath.endsWith('.js'))).toBe(true);
      
      // Check that results are sorted
      for (let i = 0; i < ranked.length - 1; i++) {
        expect(ranked[i].score).toBeGreaterThanOrEqual(ranked[i + 1].score);
      }
    });

    test('should handle complex search workflow', async () => {
      // Search with regex
      const results = await searchEngine.searchRegex('function\\s+\\w+');
      
      // Filter by file type
      const jsResults = searchEngine.filterByFileType(results, ['.js']);
      
      // Filter by directory (exclude src)
      const rootResults = jsResults.filter(r => !r.filePath.startsWith('src/'));
      
      // Rank results
      const ranked = searchEngine.rankResults(rootResults, 'function');
      
      expect(ranked.every(r => r.filePath.endsWith('.js'))).toBe(true);
      expect(ranked.every(r => !r.filePath.startsWith('src/'))).toBe(true);
    });
  });
});
